PREFIX geo: <http://www.opengis.net/ont/geosparql#>
SELECT ?station ?stationLabel
WHERE {
  wd:Q69672804 wdt:P625 ?targetCoord.
  ?station wdt:P31 wd:Q406635;
           wdt:P131 wd:Q2753;
           wdt:P625 ?coord.
  SERVICE wikibase:function {
    geof:distance(?targetCoord, ?coord, ?dist)
  }
  OPTIONAL { ?station rdfs:label ?stationLabel. FILTER(LANG(?stationLabel) = "en") }
}
ORDER BY ?dist
LIMIT 1

